// Character code → palette color name lookup
const CODE_MAP: Record<string, string> = {"0":"theme-highlight","1":"transparent","2":"outline","3":"border","4":"foot","5":"beak","6":"eye","7":"face","8":"hood","9":"eyebrow","A":"upper-eyelid","B":"upper-corner-eye","C":"behind-eye","D":"corner-eye","E":"temple","F":"lower-eyelid","G":"nose","H":"nose-tip","I":"cheek","J":"scruff","K":"chin","L":"collar","M":"collar-scruff","N":"belly","O":"underbelly","P":"wing","Q":"shoulder","R":"wing-spots","S":"wing-edge","T":"heart","U":"heart-border","V":"heart-shine","W":"feather-spine","X":"#ffd029","Y":"#70c21f","Z":"#0b49b9","a":"#76c725","b":"#ec3344","c":"#ffcb0f","d":"#1a58c7","e":"#86de30","f":"#ce935c","g":"#8f563b","h":"#e3e3e3","i":"#c9c9c9","j":"#fad19c","k":"#efc48e","l":"#c3cdd2","m":"#931520","n":"#1d5bcc","o":"#c2854c","p":"#a4a4a4","q":"#e3b476","r":"#948f96","s":"#847e87","t":"#fad78a","u":"#ecca7f","v":"#e3bf70","w":"#dab665","x":"#ea4747","y":"#5c78c7","z":"#3a59af","undefined":"#3f1b50"};

// Compact encoded birb sprite sheet: rows separated by |, each char = one pixel
// 32 rows × 320 columns (10 layers of 32×32 each)
const BIRB_ENCODED = "|||||||||||||||||||||||||||||||";

// Compact encoded hats sprite sheet: rows separated by |, each char = one pixel
// 12 rows × 132 columns (11 hats of 12×12 each)
const HATS_ENCODED = "111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111|111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111|111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111|111111111111111111111111111111111111111111111111113331111111111111111111111111111111111111111111111111111111111111111111111111111111|111111111111111111111111111111211111111111111111133033333111111111111111111111111111111111111111111111111111111111111111111111111111|11115W521111111111111111111112211111111111111111130X033Y3311111111111111111111111111111111111111111111111111111111111111111111111111|11115W521111111122221111111112Z21111111111111111133083Y8a311111222122111111112221111111112211111112111111211111111111111111111111111|1111W55211111112bTTc211111112Sd2111111111111111111333e8383111112f22g211111112hii211111112jk2011112l212212l21111122221111111111111111|1111552211111112bTTmc21111112Nn211111111222211111113322333111112ffog21111112hipp21111112jkq0X01112l22rs22l211112tuvw21111115WW522111|1111xTTT11111112bTTm22111112SSnZ21111112yyz211111132231111222HHHH2221112TH2111122H021112rs211122TT22111115W5522111|115W555222111112222221111112SSNZ21111112211111111111111112fffooogg21112hiiipp21112jjkkkqqq2111221112tuww21111WWWW111|1111111111111111111111111112222221111222222221111111111111113122222222111122222222113122222222111122222222113122222222112255WW552222";

// Decode compact string into 2D palette color name array
function decodePixels(encoded: string): string[][] {
  return encoded.split('|').map(row => row.split('').map(code => CODE_MAP[code]));
}

// Lazily decoded pixel data
let _birbPixels: string[][] | null = null;
let _hatsPixels: string[][] | null = null;

export function getBirbPixelData(): string[][] {
  if (!_birbPixels) _birbPixels = decodePixels(BIRB_ENCODED);
  return _birbPixels;
}

export function getHatsPixelData(): string[][] {
  if (!_hatsPixels) _hatsPixels = decodePixels(HATS_ENCODED);
  return _hatsPixels;
}

// Layer indices in the sprite sheet
export const LAYER_INDICES = {
  base: 0,
  down: 1,
  heartOne: 2,
  heartTwo: 3,
  heartThree: 4,
  tuftBase: 5,
  tuftDown: 6,
  wingsUp: 7,
  wingsDown: 8,
  happyEye: 9,
} as const;

export const SPRITE_WIDTH = 32;
export const SPRITE_HEIGHT = 32;
export const HAT_WIDTH = 12;

// Extract a single layer's pixels from the full sprite sheet
export function getLayerPixels(spriteSheet: string[][], spriteIndex: number, width: number): string[][] {
  const startX = spriteIndex * width;
  const pixels: string[][] = [];
  for (let y = 0; y < spriteSheet.length; y++) {
    pixels.push(spriteSheet[y].slice(startX, startX + width));
  }
  return pixels;
}
